Also, until we find the best approach to the problem and release it, you can use following shim in your code that will allow for proper null/None handling:
```python
class AllowNull(BaseField):
    """Wrapping pseudo-field that allows null values as a representation

    This is a workaround for lack of such suport in graceful but it is
    likely to change in future, see:

        https://github.com/swistakm/graceful/issues/3

    """
    def __init__(self, wraps):
        super(AllowNull, self).__init__(
            details=wraps.details,
            label=wraps.label,
            source=wraps.source,
            validators=None,
            many=wraps.many,
            read_only=wraps.read_only,
        )
        self.wraps = wraps
        self.type = wraps.type
        self.spec = wraps.spec

    def from_representation(self, data):
        if data is None:
            return None
        else:
            return self.wraps.from_representation(data)

    def to_representation(self, value):
        if value is None:
            return None
        else:
            return self.wraps.to_representation(value)

    def validate(self, value):
        return self.wraps.validate(value)

    def describe(self, **kwargs):
        return self.wraps.describe(**kwargs)
```

This is a field wrapper that can be used directly inside of your serializer class:

```python
class MySerializer(BaseSerializer):
    my_string_field = AllowNull(
        StringField("Test String Field", source='test')
    )
```

It's far from perfect but does the job.

Wow, the HTML is difficult to read... there is one minor problem which doesn't affect this issue, but some rows need quotes around the content:

```html
<tr data-tt-id=css_Tr_Questions_Employer of Choice data-tt-parent-id=Employer of Choice class='tablesorter-childRow rowheader2 ' style='display:none; '>
```

Anyway, it appears the solution is to trigger a "setFixedColumnSize" to refresh the scroller widget after toggling the child rows. This method doesn't set any fixed columns, but it does refresh the row height and total row height calculations internally.

```js
$table3.delegate('.toggle', 'click', function() {
  // ...
  $('table').trigger('setFixedColumnSize');
});
```

Try this ([demo](https://jsfiddle.net/s6nj8pcu/2/)):

```js
$(function() {

  function editComplete(el) {
    var $el = $(el),
      newContent = $el.text(),
      // there shouldn't be any colspans in the tbody
      cellIndex = el.cellIndex,
      // data-row-index stored in row id
      rowIndex = $el.closest('tr').attr('id');
    /*
    $.post("mysite.php", {
      "row": rowIndex,
      "cell": cellIndex,
      "content": newContent
    });
    */
  }

  function moveCells(el, dir) {
    var $el = $(el),
      changed = false,
      // there shouldn't be any colspans in the tbody
      cellIndex = el.cellIndex,
      $allRows = $el.closest('tbody').find('tr'),
      rowIndex = $allRows.index($el.closest('tr'));
    if (dir === "ArrowUp" && rowIndex - 1 >= 0) {
      rowIndex--;
      changed = true;
    } else if (dir === "ArrowDown" && rowIndex + 1 < $allRows.length) {
      rowIndex++;
      changed = true;
    }
    if (changed) {
      $el.blur();
      $allRows.eq(rowIndex).find('td').eq(cellIndex).find('[contenteditable]').focus();
    }
  }

  $("#table").tablesorter({
      theme: 'blue',

      widgets: ['editable'],
      widgetOptions: {
        // or "0-2" (v2.14.2); point to the columns to make editable
        // (zero-based index)
        editable_columns: [0, 1, 2],
        // press enter to accept content, or click outside if false
        editable_enterToAccept: false,
        // accepts any changes made to the table cell automatically
        editable_autoAccept: true,
        // auto resort after the content has changed.
        editable_autoResort: false,
        // return a valid string: 
        // function(text, original, columnIndex){ return text; }
        editable_validate: null,
        editable_focused: function(txt, columnIndex, $element) {
          // $element is the div, not the td
          // to get the td, use $element.closest('td')
          $element.addClass('focused');
        },
        editable_blur: function(txt, columnIndex, $element) {
          // $element is the div, not the td
          // to get the td, use $element.closest('td')
          $element.removeClass('focused');
        },
        // note $element is the div inside of the table cell, so use
        // $element.closest('td') to get the cell only select everthing
        // within the element when the content starts with the letter "B"
        editable_selectAll: function(txt, columnIndex, $element) {
          return /^b/i.test(txt) && columnIndex === 0;
        },
        // trim content inside of contenteditable
        // ( remove tabs & carriage returns )
        editable_trimContent: false,
        // wrap all editable cell content... makes this widget work in
        // IE, and with autocomplete
        editable_wrapContent: '<div>',
        // class name of cell that is not editable
        editable_noEdit: 'no-edit',
        // event fired after the table content has been edited
        editable_editComplete: 'editComplete'
      }
    })
    // config event variable new in v2.17.6
    .children('tbody').on('editComplete keyup', 'td', function(event, config) {
      if (event.type === 'editComplete') {
        editComplete(this);
      } else if (event.key.indexOf('Arrow') === 0) {
        moveCells(this, event.key);
      }
    });

});
```

