Sorry, here is the correctly formatted code

```python
import numpy as np

#pythran export lms_1st_multi (complex[:,:], complex[:], complex[:,:], float[:], int)
def lms_1st_multi (alphas, y1, inputs, ks, chunksize):
    L = y1.shape[0]
    M = alphas.shape[1]
    n_inputs = inputs.shape[0]
    zout = np.empty (L-M, dtype=complex)
    errs = np.empty ((n_inputs, M), dtype=complex)
   
    for i in range (M/2, L-M/2-1+1):
        z = y1[i]
        for inp in range (n_inputs):
            z -= np.dot (alphas[inp,:], inputs[inp, i-M/2,i+M/2+1])

        for inp in range (n_inputs):
            for j in range (M):
                w = inputs[inp,i-M/2+j]
                errs[inp,j] += z * w.conjugate()

        if i % chunksize == chunksize - 1:
            try:
                k = ks[i/chunksize]
            except:
                k = ks

            for inp in range (n_inputs):
                for j in range (M):
                    alphas[inp,j] += errs[inp,j] * k
                errs[inp,j] = 0

        zout[i-M/2] = z


    return zout
```

